def is_not_vowel_word(word):
    vowels = 'aeiouAEIOU'
    return word[0] not in vowels

def remove_vowel_words(sentence):
    words = sentence.split()
    filtered_words = filter(is_not_vowel_word, words)
    return ' '.join(filtered_words)

if __name__ == "__main__":
    input_sentence = input().strip()
    result = remove_vowel_words(input_sentence)
    print(result)
